function solve(s: string): number {
    const n = s.length;
    const prefix_L = new Array(n + 1).fill(0);
    const prefix_C = new Array(n + 1).fill(0);

    for (let i = 1; i <= n; i++) {
        prefix_L[i] = prefix_L[i - 1] + (s[i - 1] === 'L' ? 1 : 0);
        prefix_C[i] = prefix_C[i - 1] + (s[i - 1] === 'C' ? 1 : 0);
    }

    const suffix_T = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        suffix_T[i] = suffix_T[i + 1] + (s[i] === 'T' ? 1 : 0);
    }

    const C_suffix_T = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        C_suffix_T[i] = (s[i] === 'C') ? suffix_T[i] : 0;
    }

    const sum_T_after_C = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        sum_T_after_C[i] = sum_T_after_C[i + 1] + C_suffix_T[i];
    }

    const LC_pairs_prefix = new Array(n + 1).fill(0);
    for (let i = 1; i <= n; i++) {
        LC_pairs_prefix[i] = LC_pairs_prefix[i - 1];
        if (s[i - 1] === 'C') {
            LC_pairs_prefix[i] += prefix_L[i - 1];
        }
    }

    let original_count = 0;
    for (let i = 0; i < n; i++) {
        if (s[i] === 'C') {
            original_count += prefix_L[i] * suffix_T[i + 1];
        }
    }

    let max_insert_L = 0;
    for (let i = 0; i <= n; i++) {
        max_insert_L = Math.max(max_insert_L, sum_T_after_C[i]);
    }

    let max_insert_C = 0;
    for (let i = 0; i <= n; i++) {
        const l = prefix_L[i];
        const t = suffix_T[i];
        max_insert_C = Math.max(max_insert_C, l * t);
    }

    let max_insert_T = 0;
    for (let i = 0; i <= n; i++) {
        max_insert_T = Math.max(max_insert_T, LC_pairs_prefix[i]);
    }

    const max_increase = Math.max(max_insert_L, max_insert_C, max_insert_T);
    return original_count + max_increase;
